from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, jwt_required, create_access_token, get_raw_jwt
from pyjwt import decode as jwt_decode, AlgorithmInvalid
import os

app = Flask(__name__)
app.config["JWT_SECRET_KEY"] = "your-secret"
app.config["JWT_ALGORITHMS"] = ["HS256", "RS256"]
jwt = JWTManager(app)

@app.route('/token', methods=['POST'])
def generate_token():
    username = request.form["username"]
    expiry_minutes = 30
    access_token = create_access_token(identity=username, expires_delta=expiry_minutes * 60)
    return jsonify({"access_token": access_token})

@app.route('/protected')
@jwt_required()
def protected():
    try:
        jwt_data = jwt_decode(get_raw_jwt(), algorithms=["HS256", "RS256"])
        payload = jwt_data['identity']
        return jsonify({"payload": payload})
    except AlgorithmInvalid as e:
        return jsonify({"error": str(e)}), 401

if __name__ == '__main__':
    app.run(debug=True)